def sanitize_metadata(metadata):
    """
    Sanitize metadata to prevent injection attacks and limit size.
    """
    if not isinstance(metadata, dict):
        return {}
    
    sanitized = {}
    max_keys = 50
    max_value_length = 1000
    
    for key, value in list(metadata.items())[:max_keys]:
        # Only allow string keys
        if not isinstance(key, str):
            continue
            
        # Sanitize key
        clean_key = key[:100]
        
        # Handle different value types safely
        if isinstance(value, (str, int, float, bool)):
            if isinstance(value, str):
                sanitized[clean_key] = value[:max_value_length]
            else:
                sanitized[clean_key] = value
        elif isinstance(value, (list, dict)):
            # Convert to JSON string with size limit
            try:
                json_str = json.dumps(value)
                if len(json_str) <= max_value_length:
                    sanitized[clean_key] = value
            except (TypeError, ValueError):
                pass
    
    return sanitized


